def links():
 for route,pdf in DOCUMENT_PDFS.items():
  p=ROOT/route;text=p.read_text()
  if pdf not in text:text=text.replace('<div class="doc-actions">',f'<div class="doc-actions"><a href="{pdf}" download>Download PDF</a>',1)
