def pdfs():
 for route,pdf in DOCUMENT_PDFS.items():
  out=ROOT/pdf;out.parent.mkdir(exist_ok=True);HTML(filename=str(ROOT/route),base_url=str(ROOT)).write_pdf(str(out))
  if out.stat().st_size<1000:raise RuntimeError(str(out))
